   266→inline float calculateDistance(const short measuredPower, const short rssi, const float a, const float b, const float c) {
   267→    if (rssi == 0) {
   268→        return -1.0; // if we cannot determine distance, return -1.
   269→    }
   270→    float ratio = rssi * 1.0 / measuredPower;
   271→    if (ratio < 1.0) {
   272→        return pow(ratio,10);
   273→    }
   274→    else {
   275→        float distance =  (a)*pow(ratio,b) + c;
   276→        return distance;
   277→    }
   278→}
