    31→template <typename T>
    32→struct Observable {
    33→    T value;
    34→    unordered_map<size_t, function<void(const T&)>> listenerMap;
    35→    atomic<size_t> nextID{0};
    36→    mutex mtx;
    37→    
    38→    explicit Observable(const T& val) : value(val) {}
    39→    
    40→    size_t addListener(const function<void(const T&)>& listener, bool fireImmediately = true) {
    41→        lock_guard<mutex> lock(mtx);
    42→        size_t id = nextID++;
    43→        listenerMap[id] = listener;
    44→        if (fireImmediately) {
    45→            try {
    46→                listener(value);  // 立即执行回调
    47→            } catch (...) {
    48→                // 异常处理（可选）
    49→            }
    50→        }
    51→        return id;
    52→    }
    53→    
    54→    bool removeListener(size_t id) {
    55→        lock_guard<mutex> lock(mtx);
    56→        return listenerMap.erase(id) > 0;
    57→    }
    58→    
    59→    Observable& operator=(const T& newVal) {
    60→        if (value != newVal) {
    61→            value = newVal;
    62→            decltype(listenerMap) localCopy;
    63→            {
    64→                lock_guard<mutex> lock(mtx);
    65→                localCopy = listenerMap; // 复制避免死锁
    66→            }
    67→            for (const auto& [id, listener] : localCopy) {
    68→                listener(value);
    69→            }
    70→        }
    71→        return *this;
    72→    }
    73→    
    74→    operator T() const { return value; }
    75→};
